import{_ as i,o as l,c as e,a3 as t}from"./chunks/framework.gsMzR_Kb.js";const u=JSON.parse('{"title":"阴阳","description":"阴阳是进入道家与易经最先要稳住的结构感，不是神秘词，而是观察关系的方式。","frontmatter":{"title":"阴阳","description":"阴阳是进入道家与易经最先要稳住的结构感，不是神秘词，而是观察关系的方式。","category":"guide","aliases":["阴阳","阴阳专题","yin yang"]},"headers":[],"relativePath":"topics/yin-yang.md","filePath":"topics/yin-yang.md","lastUpdated":1777132262000}'),r={name:"topics/yin-yang.md"};function o(n,a,s,h,d,c){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="阴阳" tabindex="-1">阴阳 <a class="header-anchor" href="#阴阳" aria-label="Permalink to &quot;阴阳&quot;">​</a></h1><h2 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h2><p>阴阳不是两个抽象标签，而是一种最基本的观察框架。</p><p>它帮助人看到：</p><ul><li>事物并非只有单一面向</li><li>许多关系都是相对生成的</li><li>对立之中常含互根、互感、互转</li></ul><p>所以阴阳更像一种“怎么看世界”的方式，而不只是“背两个名词”。</p><h2 id="为什么重要" tabindex="-1">为什么重要 <a class="header-anchor" href="#为什么重要" aria-label="Permalink to &quot;为什么重要&quot;">​</a></h2><p>如果阴阳这一层没有先稳住，后面很多词都会发散。</p><ul><li>读《易》时，看不懂卦爻为什么这样分</li><li>读道家时，容易把“反者道之动”读成纯粹玄谈</li><li>看现实问题时，也容易只站一边，不会看关系流动</li></ul><p>阴阳的重要，不在于它包打天下，而在于它让人先学会不把世界看成单线条。</p><h2 id="怎么读-怎么进入" tabindex="-1">怎么读 / 怎么进入 <a class="header-anchor" href="#怎么读-怎么进入" aria-label="Permalink to &quot;怎么读 / 怎么进入&quot;">​</a></h2><p>建议按这条线进入：</p><ol><li>先把阴阳读成关系，而不是实体</li><li>再把阴阳放回《易经》卦爻系统里看</li><li>最后才把它扩展到更广的道家与现实理解中</li></ol><p>今天若要快速进入，可以先问自己三个问题：</p><ul><li>我现在看到的是单边结论，还是双方关系？</li><li>我把变化看成突变，还是互相推移？</li><li>我是不是总想分对错，却忘了看时机与位置？</li></ul><h2 id="相关原典" tabindex="-1">相关原典 <a class="header-anchor" href="#相关原典" aria-label="Permalink to &quot;相关原典&quot;">​</a></h2><ul><li>《周易》</li><li>《系辞上传》</li><li>《说卦传》</li><li>《道德经》</li></ul><h2 id="我的理解" tabindex="-1">我的理解 <a class="header-anchor" href="#我的理解" aria-label="Permalink to &quot;我的理解&quot;">​</a></h2><p>待补：这里先留给后续续读时，把自己的体会与现实例子补进来。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《周易》</li><li>《系辞上传》</li><li><a href="/Dao/yijing/basics/concepts/yin-yang">易经概念：阴阳</a></li></ul>',21)])])}const _=i(r,[["render",o]]);export{u as __pageData,_ as default};
